<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF">create</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379"> user</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379"> 'test1'@'localhost'</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379"> identified</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379"> by</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379"> 'test1'</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">;</span></span>
